function LGameUI.GetRootPreAsset()
	local rootPreAssetTrans = LGameUI.RootPreAssetTrans
	if not rootPreAssetTrans then
		rootPreAssetTrans = CS.FindObject(LGameUI.ROOT_PRE_ASSET_PATH)
		LGameUI.RootPreAssetTrans = rootPreAssetTrans
	end
	return rootPreAssetTrans
end

function LGameUI.GetCSUIPreAsset()
	local uiPreAssetComponent = LGameUI.CSUIPreAsset
	if uiPreAssetComponent then
		return uiPreAssetComponent
	end
	uiPreAssetComponent = LGameUI.GetRootPreAsset():GetComponent(typeUIPreAsset)
	LGameUI.CSUIPreAsset = uiPreAssetComponent
	return uiPreAssetComponent
end

