function LGameUI:Initialize()
	LxBaseMgr.Initialize(self)

	self._destroyCount = 0

	self._csUICamera = nil                -- ui camera

	---@type LUiClickEffector
	self._uiClickEffector = nil            -- touch effect

	self._uiCanvasList = nil            -- list = {[k]=v,...} (k=layer, v=canvas transform)
	self._openWndKeyAuto = 0            -- 当前窗口列表递增KEY最大值

	---@type string[]
	self._openWndList_wndName = nil    -- k=wndName, v={ wndClass,wndClass,wndClass }
	---@type table<number, LWnd[]>
	self._openWndList_sortLayer = nil    -- k=sortlayer, v={ wndClass,wndClass,wndClass }
	self._bCleaning = nil                -- is cleaning

	---@type UIBlockWait
	self._waitWndClass = nil            -- sys wait wnd
	self._openWndAniCnt = 0

	self._backWndMap_wndName = nil
	self._backWndListMap_wndName = nil
	self._isVisibleAllUI = true
	self._isVisibleBattleFont = true

	local uiRoot = LGameUI.GetUIRoot()
	local trans = CS.FindTrans(uiRoot, LGameUI.UICAMERA_PATH)
	self._csUICamera = trans:GetComponent(typeofCamera)
	local uiCanvasRoot = LGameUI.GetUICanvasRoot()
	local uiCanvasList = {}
	uiCanvasList[LGameUI.UI_SORTLAYER_UIBOTTOM] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIBOTTOM)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIWND] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIWND)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIUP] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIUP)
	uiCanvasList[LGameUI.UI_SORTLAYER_UITOP] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UITOP)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIGUIDE] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIGUIDE)
	uiCanvasList[LGameUI.UI_SORTLAYER_UILOADING] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UILOADING)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIWAIT] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIWAIT)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIDEBUG] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIDEBUG)
	uiCanvasList[LGameUI.UI_SORTLAYER_UITOUCH] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UITOUCH)
	self._uiCanvasList = uiCanvasList

	self._openWndList_wndName = {}
	self._openWndList_sortLayer = {}
end

function LGameUI:Dispose()
	LGameUI.CSUIPreAsset = nil
	LGameUI.RootPreAssetTrans = nil

	_destroyCount = nil
	
	local uiClickEffect = self._uiClickEffector
	if uiClickEffect then
		uiClickEffect:Destroy()
		uiClickEffect = nil
		self._uiClickEffector = nil
	end

	if self._screenShot then
		self._screenShot:Destroy()
		self._screenShot = nil
	end

	self._bDestroying = true--正在清理窗口，不允许创建新窗口和通过其他函数删除窗口

	self._waitWndClass = nil

	local wndLayerList = self._openWndList_sortLayer

	self._wndBlurLayerList = {}

	self._openWndList_wndName = {}
	self._openWndList_sortLayer = {}

	local layerNameList = LGameUI.LAYER_NAME_LIST
	local layerCnt = #layerNameList
	local wndList
	local layerName
	local wndCnt
	local wnd
	for i = layerCnt, 1, -1 do
		layerName = layerNameList[i]
		wndList = wndLayerList[layerName]
		wndLayerList[layerName] = nil
		if wndList then
			wndCnt = #wndList
			for k=wndCnt, 1, -1 do
				wnd = wndList[k]
				if not wnd:IsWndClosed() then
					wnd:ForceShutdown()
				end
			end
		end
	end
	LxBaseMgr.Dispose(self)
end

function LGameUI:CleanUpWnd()
	self._bDestroying = true --正在清理窗口，不允许创建新窗口和通过其他函数删除窗口

	local wndLayerList = self._openWndList_sortLayer
	local wndOpenListForName = self._openWndList_wndName
	local layerNameList = LGameUI.LAYER_NAME_LIST
	local layerCnt = #layerNameList
	local wndList
	local layerName
	local wndCnt
	local wnd
	local wndClassName
	local wndBlurLayerList = self._wndBlurLayerList or {}
	for i = layerCnt, 1, -1 do
		layerName = layerNameList[i]
		wndList = wndLayerList[layerName]
		if wndList then
			wndCnt = #wndList
			for k=wndCnt, 1, -1 do
				wnd = wndList[k]
				wndClassName = wnd:GetClassName()
				if not LGameUI.NO_CLEAN_CLOSE_WND_LIST[wndClassName] then
					wndBlurLayerList[wnd:GetWndKey()] = nil
					if not wnd:IsWndClosed() then
						wnd:ForceShutdown()
					end
					table.remove(wndList, k)
					table.removeidata(wndOpenListForName[wndClassName] or {}, wnd)
				end
			end
		end
	end
	self:UpdateItemListFrozen()
	self._bDestroying = nil
end

function LGameUI:Create()
	LBaseManager.Create(self)
	local uiRoot = LGameUI.GetUIRoot()
	local trans = CS.FindTrans(uiRoot, LGameUI.UICAMERA_PATH)
	self._csUICamera = trans:GetComponent(typeofCamera)
	local uiCanvasRoot = LGameUI.GetUICanvasRoot()
	local uiCanvasList = {}
	uiCanvasList[LGameUI.UI_SORTLAYER_UIBOTTOM] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIBOTTOM)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIWND] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIWND)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIUP] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIUP)
	uiCanvasList[LGameUI.UI_SORTLAYER_UITOP] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UITOP)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIGUIDE] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIGUIDE)
	uiCanvasList[LGameUI.UI_SORTLAYER_UILOADING] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UILOADING)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIWAIT] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIWAIT)
	uiCanvasList[LGameUI.UI_SORTLAYER_UIDEBUG] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UIDEBUG)
	uiCanvasList[LGameUI.UI_SORTLAYER_UITOUCH] = CS.FindTrans(uiCanvasRoot, LGameUI.UI_SORTLAYER_UITOUCH)
	self._uiCanvasList = uiCanvasList

	self._openWndList_wndName = {}
	self._openWndList_sortLayer = {}

	return true
end

function LGameUI:DoAfterInitialize()
	self:InitClickEffector()
	self:InitScreenShot()
end

-----------------------------------------------------------------
function LGameUI:InitScreenShot()
	local screenShot = LScreenShot:New()
	local rootGame = CS.FindObject(LGameUI.ROOT_GAME).transform
	local rootScreenShot = CS.FindTrans(rootGame, "RootScreenShot").gameObject
	if(not screenShot:Create(rootScreenShot,self._csUICamera)) then
		screenShot:Destroy()
		screenShot = nil
	end
	self._screenShot = screenShot
end

function LGameUI:CaptureUIScreen(wndTrans, tblUITrans, isShare, shareData,callback)
	if not self._screenShot then return end
	self._screenShot:CaptureUIScreen(wndTrans, tblUITrans, isShare, shareData,callback)
end

function LGameUI:OnScreenShotResult(isOk)
	if not self._screenShot then return end
	self._screenShot:OnScreenShotResult(isOk)
end

function LGameUI:OnApplicationPause(isPause)
	-- 退出后台，先暂停所有界面的定时器
	local wndLayerList = self._openWndList_sortLayer
	local layerNameList = LGameUI.LAYER_NAME_LIST
	local wndList
	for _t, layerName in ipairs(layerNameList) do
		wndList = wndLayerList[layerName]
		if wndList then
			for _k,wnd in ipairs(wndList) do
				if not wnd:IsWndClosed() then
					wnd:TimePauseAll(isPause)
				end
			end
		end
	end
end

-----------------------------------------------------------------
function LGameUI:InitClickEffector()
	local clickEffector = LUiClickEffector:New()
	if (not clickEffector:Create()) then
		clickEffector:Destroy()
		clickEffector = nil
	end
	self._uiClickEffector = clickEffector
end


function LGameUI:EnableTouchEffect(b)
	local clickEffector = self._uiClickEffector
	if (clickEffector) then
		clickEffector:EnableTouchEffect(b)
	end
end

function LGameUI:ResetTouchTime()
	local touchEffect = self._uiClickEffector
	if (touchEffect) then
		touchEffect:ResetTouchTime()
	end
end

