	for k,v in pairs(self._openWndList_wndName) do
		local wnd = self:FindFirstWndByName(k)
		if (wnd and not wnd:IsWndClosed()) then
			if wnd:GetWndName() == "UIGMnBtn" then

			elseif wnd:GetWndName() == "UIWGLDebugBtn" then

			else
				wnd:SetWndVisible(isShow)
			end

