function LGameUI:SetVisibleBattleFont(isShow)
	self._isVisibleBattleFont = isShow

	--设置对战UI界面
	local wnd = self:FindFirstWndByName("UIFightPrepare")
	if wnd and not wnd:IsWndClosed() then
		wnd:SetAllUIVisible(isShow)
