	wnd = self:FindFirstWndByName("UIFight")
	if wnd and not wnd:IsWndClosed() then
		wnd:SetAllUIVisible(isShow)
		wnd:SetAllUIRedVisible(isShow)
	end

	wnd = self:FindFirstWndByName("UISayFlow")
	if wnd and not wnd:IsWndClosed() then
