--关闭指定名字窗口
function LGameUI:CloseWndByName(wndName)
	local wndList = self:FindWndByName(wndName)
	if wndList then
		for i = #wndList, 1, -1 do
			wndList[i]:WndClose()
		end
	end
end
-- 关闭最上层窗口
function LGameUI:CloseWndByLast()
	local openWndList = self._openWndList_sortLayer[LGameUI.UI_SORTLAYER_UIWND]
	if not openWndList then return end
	local wndCnt = #openWndList
	local wnd
	for i = wndCnt, 1, -1 do
		wnd = openWndList[i]
		local wndName = wnd:GetClassName()
		if (not LGameUI.NO_AUTO_CLOSE_WND_LIST[wndName]) then
			--FireEvent(EventNames.SEND_HISTROY_WND,wndName)
			wnd:WndClose()
			break
		end
	end
end

function LGameUI:FindLastWnd(ignoreRecord)

	local list = {
		LGameUI.UI_SORTLAYER_UIGUIDE,
		LGameUI.UI_SORTLAYER_UIWND,
	}

	for k,v in ipairs(list) do
		local openWndList = self._openWndList_sortLayer[v]
		if openWndList then
			local wndCnt = #openWndList
			local wnd
			for i = wndCnt, 1, -1 do
				wnd = openWndList[i]
				local wndName = wnd:GetClassName()
				if not ignoreRecord[wndName] then
					if wndName == "UIGue" then
						local curGuide = wnd:GetCurGuide() or -1
						if curGuide > 0 then
							return wnd
						end
					else
						return wnd
					end
				end
			end
		end

	end

end

function LGameUI:CloseWndByLayer(layer,excepts)
	excepts = excepts or {}
	local wndList = self._openWndList_sortLayer[layer]
	if not wndList then
		return
	end
	local wndCnt = #wndList
	for i = wndCnt, 1, -1 do
		local wnd = wndList[i]
		if wnd then
			local wndName = wnd:GetClassName()
			local isExcept = excepts[wndName]
			if not isExcept and not LGameUI.ALL_CLOSE_EXCEPTS[wndName]  then
				wnd:WndClose()
			end
		end 		
	end
end

function LGameUI:GenerateRecordHistoryList(extraWnds,sortLayer,isClose)
	extraWnds = extraWnds or {}

	local wndLayerList = self._openWndList_sortLayer
	local list = {}
	local wndCnt
	local wnd
	local wndName
	local wndList

	if(sortLayer) then
		wndList = wndLayerList[sortLayer]
		if wndList then
			wndCnt = #wndList
			for i=wndCnt , 1, -1 do
				wnd = wndList[i]
				wndName = wnd:GetClassName()

				if not LGameUI.ALL_CLOSE_EXCEPTS[wndName] and
						not LGameUI.NO_RECORD_HISTORY[wndName] and
						not wnd:IsWndClosed() then

					local historyData = wnd:GetHistory()
					if(historyData) then table.insert(list, historyData) end
					if isClose then
						wnd:WndClose()
					end

				end
			end
		end
	else
		local layerNameList = LGameUI.LAYER_NAME_LIST
		for i=#layerNameList, 1, -1  do
			local layerName = layerNameList[i]
			wndList = wndLayerList[layerName]
			if wndList then
				wndCnt = #wndList
				for i=wndCnt , 1, -1 do
					wnd = wndList[i]
					wndName = wnd:GetClassName()

					if not extraWnds[wndName] and
							not LGameUI.ALL_CLOSE_EXCEPTS[wndName] and
							not LGameUI.NO_RECORD_HISTORY[wndName] and
							not wnd:IsWndClosed() then

						local historyData = wnd:GetHistory()
						if(historyData) then table.insert(list, historyData) end
						if isClose then
							wnd:WndClose()
						end

					end
				end
			end
		end
	end


	return list
end

function LGameUI:GetCurrentUI(noOpenSelWndList)
	local list = {}
	local wndCnt
	local wnd
	local wndName
	local wndList
	noOpenSelWndList = noOpenSelWndList or {}
	local wndLayerList = self._openWndList_sortLayer
	local layerNameList = LGameUI.LAYER_NAME_LIST
	for i=#layerNameList, 1, -1  do
		local layerName = layerNameList[i]
		wndList = wndLayerList[layerName]
		if wndList then
			wndCnt = #wndList
			for i=wndCnt , 1, -1 do
				wnd = wndList[i]
				wndName = wnd:GetClassName()
				local isNoOpen = noOpenSelWndList[wndName] ~= nil
				if not isNoOpen and not LGameUI.ALL_CLOSE_EXCEPTS[wndName] and not LGameUI.NO_RECORD_HISTORY[wndName] then
					local historyData = wnd:GetHistory()
					if historyData then
						table.insert(list, historyData)
					end
				end
			end
		end
	end
	return list
end

function LGameUI:CloseAllButExcept(extraWnds)
	extraWnds = extraWnds or {}
	if gModelGuide:IsJumpFeedScene() then
		extraWnds["UIGjAward"] = true
		extraWnds["UIGBuy"] = true
		extraWnds["UIActHappyLottery"] = true
		extraWnds["UIMotifActEntrance_6"] = true
	end
	local wndCnt
	local wnd
	local wndName
	local wndList
	local wndLayerList = self._openWndList_sortLayer
	local layerNameList = LGameUI.LAYER_NAME_LIST
	for i=#layerNameList, 1, -1  do
		local layerName = layerNameList[i]
		wndList = wndLayerList[layerName]
		if wndList then
			wndCnt = #wndList
			local needCloseList = {}
			for i=wndCnt , 1, -1 do
				wnd = wndList[i]
				if wnd then
					wndName = wnd:GetClassName()
					if not LGameUI.ALL_CLOSE_EXCEPTS[wndName] and not extraWnds[wndName] then
						table.insert(needCloseList,wnd)
					end
				end
			end

			for k,v in ipairs(needCloseList) do
				v:WndClose()
			end
		end
	end
end

function LGameUI:CloseAllBySwitchTypeButExcept(switchType, extraWnds)
	extraWnds = extraWnds or {}
	local wndCnt
	local wnd
	local wndName
	local wndList
	local wndLayerList = self._openWndList_sortLayer
	local layerNameList = LGameUI.LAYER_NAME_LIST
	for i=#layerNameList, 1, -1  do
		local layerName = layerNameList[i]
		wndList = wndLayerList[layerName]
		if wndList then
			wndCnt = #wndList
			local closeWndList = {}
			for i=wndCnt , 1, -1 do
				wnd = wndList[i]
				if wnd and not wnd:IsWndClosed() then
					wndName = wnd:GetClassName()
					local wndSwitchType = wnd:GetWndSwitchType() or 0
					if not extraWnds[wndName] and wndSwitchType == switchType then
						table.insert(closeWndList,wnd)
					end
				end
			end

			for k,v in ipairs(closeWndList) do
				if not v:IsWndClosed() then
					v:WndClose()
				end
			end
		end
	end
end
