--- wnd open
------------------------------------------------------------------
function LGameUI:OpenWndWithLayer(sortLayer, wndName, argList)
	if LOG_INFO_ENABLED then
		printErrorN2("UI", string.format("--->> %s 打开在 %s ", wndName, sortLayer))
	end
	if gLGameLanguage:IsChinaRegion() and CS.IsWebGL() and LWxHelper.IsWxPlatform() then
		if PRODUCT_G_VER ~= 0 and wndName == "UIHuiYPay" then
			return
		end
	end

	-- 打开窗口之前，检查资源是否已经存在
	-- local wndPrefabName = gLGameLanguage:GetPrefabName(wndName)
	-- local resPath = CS.ResPath(CS.RES_UI_WND, wndPrefabName)
	-- local bundleName = CS.FormatBundleNameByPath(resPath)
	-- if not LResDownload:CheckRes(bundleName) then
	-- 	LResDownload:TryGetRes(bundleName)
	-- 	FireEvent(EventNames.DOWNLOAD_RES_SHOW, {type = 1, resName = wndName, bundleName = bundleName, param = {argList = argList, sortLayer = sortLayer}})
	-- 	return
	-- end

	--if LWnd.MASK_INPUT_STATUS == 0 then
	--	if wndName == "UINuoardUI" then
	--		return
	--	end
	--end

	if self._bDestroying then return end

	if LWnd.MASK_INPUT_STATUS == 0 then
		local forbidLayerWnd = self._maskInputWndList
		if not forbidLayerWnd then
			forbidLayerWnd = {
				["UISayAirWin"] = true,
				["UISayPop"] = true,
				["UISayFlow"] = true,
				["UISagaComment"] = true,
				["UIBulletSaySendPop"] = true,
				["UIInvasionSay"] = true,
			}
			self._maskInputWndList = forbidLayerWnd
		end
		if forbidLayerWnd[wndName] then
			return
		end
	end


	--local wndPara = {
	--	wndName= wndName,
	--	para1 = argList and argList["page"],
	--	para2 = argList and argList["subPage"],
	--	argList = argList
	--}
    --
	--FireEvent(EventNames.ON_WND_OPEN_TRIGGER,wndPara) --指引触发条件

	local wnd = self:FindFirstWndByName(wndName)
	if (wnd and not wnd:IsWndClosed()) then
		if (wnd:IsWndMode(LWnd.WND_MODE_UNIQUE)) then
			local wndSortLayer = wnd:GetWndSortLayer()
			local layerWndList = self._openWndList_sortLayer[wndSortLayer]
			table.removeidata(layerWndList, wnd)
			self:InsertIntoWndList(layerWndList, wnd)
			self:SortWndSiblingIndex(wndSortLayer)
			wnd:SetWndVisible(true)
			wnd:RefreshWhenOpen(argList)
			self:ChangeMainCityShow()
			if wnd:IsWndValid() then
				self:UpdateItemListFrozen(wnd, true)
			end
			return wnd
		end
	end
	return self:CreateWnd(sortLayer, wndName, argList)
end
------------------------------------------------------------------
--- check sort wnd sibling index
------------------------------------------------------------------
function LGameUI:SortWndSiblingIndex(sortLayer)
	local wndList = self._openWndList_sortLayer[sortLayer] or {}
	local siblingIndex = 0
	local wndTrans
	for k, v in ipairs(wndList) do
		wndTrans = v:GetWndTrans()
		if CS.IsValidObject(wndTrans) then
			if wndTrans:GetSiblingIndex() ~= siblingIndex then
				wndTrans:SetSiblingIndex(siblingIndex)
			end
			v:TrySetWndSortOrder(k)
			siblingIndex = siblingIndex + 1
		end
	end
end

------------------------------------------------------------------
--- update itemList frozen
--- 界面高斯模糊的时候，底部的自适应列表会一直滑动，原因如下
--- 界面做高斯模糊的时候UI相机目标会设置到一张跟屏幕大小不一致的贴图上
--- 可能引起界面高度进行改变，因而引起SuperGridView 和 SuperLoopList列表的计算可视区域误差而引起的列表内容需要进行变化
--- 因此把高斯模糊底部的 SuperGridView 和 SuperLoopList 禁用了
------------------------------------------------------------------
function LGameUI:UpdateItemListFrozen(wndClass, loaded)
	if wndClass then
		local wndSortLayer = wndClass:GetWndSortLayer()
		if wndSortLayer ~= LGameUI.UI_SORTLAYER_UIWND then return end
		local wndKey = wndClass:GetWndKey()
		if loaded then
			local trans = wndClass:GetWndTrans()
			local blurLayer = trans:GetComponentInChildren(typePostProcessBlurLayer)
			if not blurLayer then return end
			local list = self._wndBlurLayerList or {}
			list[wndKey] = blurLayer
			self._wndBlurLayerList = list
		else
			local list = self._wndBlurLayerList or {}
			local blurLayer = list[wndKey]
			if not blurLayer then return end
			list[wndKey] = nil
			blurLayer.enabled = false
		end
	end

	local layerWndList = self._openWndList_sortLayer[LGameUI.UI_SORTLAYER_UIWND] or {}
	local len =  #layerWndList
	if len == 0 then return end
	local bFrozen = false
	local wndBlurLayerList = self._wndBlurLayerList or {}
	--最顶部的blur 高斯模糊界面开始，被他盖住的界面，super 列表都要 冻住
	for k=len , 1, -1 do
		local wnd = layerWndList[k]
		local key = wnd:GetWndKey()
		if wnd:IsWndValid() then
			wnd:FreezeUIScroll(bFrozen)
			if not bFrozen and wndBlurLayerList[key] then
				bFrozen = true
			end
		end
	end
end
