function LGameUI:OnWndClose(wndClass)
	if self._bDestroying then return true end
	local wndName = wndClass:GetWndName()
	if LOG_INFO_ENABLED then
		printErrorN2("UI", string.format("--->> %s 关闭",wndName))
	end
	self:RemoveWnd(wndClass)
	self:OnBackWndClose(wndName)
	--if not self._closeWndList then
	--	self._closeWndList = {}
	--end
	--table.insert(self._closeWndList,wndClass)
	local sortLayer = wndClass:GetWndSortLayer()
	if (sortLayer == LGameUI.UI_SORTLAYER_UIWND) then
		local wndList = self._openWndList_sortLayer[sortLayer]
		if (not wndList or #wndList <= 0) then
			self:OnClearUIBundle()
		end
	end
	self:UpdateItemListFrozen(wndClass, false)
end

function LGameUI:OnWndCreate(wndClass)
	if self._bDestroying then return true end
	local wndName = wndClass:GetWndName()
	
	self:InsertWnd(wndClass)
	self:CheckPopWnd()
	self:OnBackWndCreate(wndName)
end

function LGameUI:OnWndLoaded(wndClass)
	local wndTrans = wndClass:GetWndTrans()
	local parentCanvas = self:FindWndParentCanvas(wndClass:GetWndSortLayer())
	wndTrans:SetParent(parentCanvas, true)
	wndTrans.localScale = Vector3.one
	wndTrans.localPosition = Vector3(0, 0, 0)
	wndTrans.anchorMin = Vector2.zero
	wndTrans.anchorMax = Vector2.one

	LNotchUtil.AdjustNotchWndAnchor(wndTrans, wndClass:GetAutoAdjustNotch())

	wndTrans.pivot = Vector2(0.5, 0.5)
	wndTrans.offsetMin = Vector2.zero
	wndTrans.offsetMax = Vector2.zero

	wndTrans.name = wndClass:GetWndName()
	self:SortWndSiblingIndex(wndClass:GetWndSortLayer())
	self:UpdateItemListFrozen(wndClass, true)
end

function LGameUI:CreateWnd(layer, wndName, argList)
	local wndRef = LxRequire(LGameUI.UIWND_PATH .. wndName)
	if (wndRef) then
		local wndClass = wndRef:New()
		wndClass:SetWndSortLayer(layer)
		if (wndClass:Create(wndName, argList)) then
			return wndClass
		else
			wndClass = nil
		end
	end
	return nil
end

function LGameUI:RemoveWnd(wndClass)
	local wndListForName = self._openWndList_wndName[wndClass:GetWndName()]
	if (wndListForName) then
		table.removeidata(wndListForName, wndClass)
	end
	
	local wndSortLayer = wndClass:GetWndSortLayer()
	local wndList = self._openWndList_sortLayer[wndSortLayer]
	if (wndList) then
		table.removeidata(wndList, wndClass)
	end

	if(wndList and wndSortLayer == LGameUI.UI_SORTLAYER_UIWND) then
		if self:SortUIWndLayer(wndList) then
			self:SortWndSiblingIndex(wndSortLayer)
		end
	end

	self:ChangeMainCityShow()
	self:CheckPopWnd()
end

function LGameUI:InsertWnd(wndClass)
	local wndKey = self._openWndKeyAuto + 1
	self._openWndKeyAuto = wndKey
	wndClass:SetWndKey(wndKey)

	local wndName = wndClass:GetWndName()
	local openWndList_wndName = self._openWndList_wndName
	local wndListForName = openWndList_wndName[wndName]
	if (not wndListForName) then
		wndListForName = {}
		openWndList_wndName[wndName] = wndListForName
	end
	table.insert(wndListForName, wndClass)

	local sortLayer = wndClass:GetWndSortLayer()
	local openWndList_sortLayer = self._openWndList_sortLayer
	local wndList = openWndList_sortLayer[sortLayer]
	if (not wndList) then
		wndList = {}
		openWndList_sortLayer[sortLayer] = wndList
	end
	self:InsertIntoWndList(wndList, wndClass)

	self:ChangeMainCityShow()

end

function LGameUI:InsertIntoWndList(wndList, wndClass)
	local cmpPropertyOrderInLayer = wndClass:GetPropertyOrderInLayer()
	local wndCnt = #wndList
	local wnd
	local curWndName = wndClass:GetWndName()
	local insertIndex = 1
	for i = wndCnt,1,-1 do
		wnd = wndList[i]
		if not wnd:IsWndClosed() and not wnd:IsUIMCity() then
			local tmpPropertyOrderInLayer = wnd:GetPropertyOrderInLayer()
			if tmpPropertyOrderInLayer <= cmpPropertyOrderInLayer then
				insertIndex = i + 1
				break
			end
		end
	end
	--printInfoN("1--------------insert index = "..insertIndex)

	if LGameUI.ABOVE_RELATIVE_WND_LIST[curWndName] then
		for i=wndCnt, 1, -1 do
			wnd = wndList[i]
			if not wnd:IsWndClosed() and not wnd:IsUIMCity() then
				if wnd:IsAboveWnd() then
					insertIndex = i
					break
				end
			end
		end
	end

	local isBelow,specialJudge = wndClass:IsBelowSpecial()
	if isBelow then
		for i=wndCnt, 1, -1 do
			wnd = wndList[i]
			if not wnd:IsWndClosed() and not wnd:IsUIMCity() then
				local wndName = wnd:GetWndName()
				if specialJudge[wndName] then
					insertIndex = i
					break
				end
			end
		end

	end

	--printInfoN("2------------------insert index = "..insertIndex)


	table.insert(wndList, insertIndex, wndClass)

	if(wndList and wndClass:GetWndSortLayer() == LGameUI.UI_SORTLAYER_UIWND) then
		self:SortUIWndLayer(wndList, true)
	end
end

function LGameUI:SortUIWndLayer(wndList, fromInsert)
	local wndCnt = #wndList
	-- 需要把主界面移动到设置了主界面之下的最后一个界面上
	local mainIndex = 0
	for i=wndCnt, 1, -1 do
		local mainWnd = wndList[i]
		if mainWnd:IsUIMCity() then
			mainIndex = i
			break
		end
	end

	if mainIndex > 0 then
		-- 查找主界面插入位置
		local firstIndex = 0
		for i=wndCnt, 1, -1 do
			local wnd = wndList[i]
			if not wnd:IsWndClosed() and wnd:IsUnderMainCity() then
				firstIndex = i
				break
			end
		end
		if fromInsert and firstIndex > 0 then
			FireEvent(EventNames.SHOW_MAIN_MORE_FUN, false)
		end
		if firstIndex < mainIndex then
			if firstIndex + 1 == mainIndex then
				return
			end
			local mainWnd = table.remove(wndList, mainIndex)
			table.insert(wndList, firstIndex + 1, mainWnd)
			return true
		else
			--中间移除了一位，实际下标减1，因此插入的位置就是firstIndex
			if firstIndex == mainIndex then
				return
			end
			local mainWnd = table.remove(wndList, mainIndex)
			table.insert(wndList, firstIndex, mainWnd)
			return true
		end

	end
end

