function LGameUI:IsSortLayerLower(oldSortLayer,newSortLayer)
	local oldIndex = LGameUI.SORT_LAYER_PRIORITY[oldSortLayer]  or 1
	local newIndex = LGameUI.SORT_LAYER_PRIORITY[newSortLayer]  or 1
	return newIndex<oldIndex
end

function LGameUI:RecordChildWnd(childWndClass)
	if not self._childWnds then
		self._childWnds ={}
	end
	local wndName = childWndClass:GetWndName()
	self._childWnds[wndName] = childWndClass
end

function LGameUI:RemoveChildWnd(wndName)
	if not self._childWnds then
		return
	end
	self._childWnds[wndName] =nil
end

function LGameUI:ClearChildWndRecord()
	self._childWnds ={}
end

function LGameUI:FindChildWndByName(wndName)
	if self._childWnds then
		return self._childWnds[wndName]
	end
end

function LGameUI:DoAdjustNotchWndAnchor()
	local wndLayerList = self._openWndList_sortLayer

	local layerNameList = LGameUI.LAYER_NAME_LIST
	local layerCnt = #layerNameList

	local wndList
	local layerName
	local wndCnt
	local wnd

	for i = layerCnt, 1, -1 do
		layerName = layerNameList[i]
		wndList = wndLayerList[layerName]
		if wndList then
			wndCnt = #wndList
			for k=wndCnt, 1, -1 do
				wnd = wndList[k]
				if wnd:IsWndValid() then
					LNotchUtil.AdjustNotchWndAnchor(wnd:GetWndTrans(), wnd:GetAutoAdjustNotch())
				end
			end
		end
	end
end

function LGameUI:CheckShowHurdle()
	local isShow = true
	local wnd = self:FindMainAffectWnd()
	if wnd then
		if wnd:IsHideHurdle() then
			isShow = false
		end
	end
	FireEvent(EventNames.SHOW_MAIN_HURDLE,isShow)
end

function LGameUI:CheckShowMainTop()
	local isShow = true

	local wnd = self:FindMainAffectWnd()
	if wnd then
		if wnd:IsHideTop() then
			isShow = false
		end
	end

	if self:IsHideMainByMap() then
		isShow =false
	end

	FireEvent(EventNames.SHOW_MAIN_TOP,isShow)

end

function LGameUI:CheckShowMainBottom()
	local isShow = true
	local wnd = self:FindMainAffectWnd()
	if wnd then
		if wnd:IsHideBottom() then
			isShow = false
		end
	end

	if self:IsHideMainByMap() then
		isShow =false
	end

	FireEvent(EventNames.SHOW_MAIN_BOTTOM,isShow)
end

function LGameUI:IsHideMainByMap()
	local curMap = GF.GetCurMap()
	if curMap and curMap:IsHideMain() then
		return true
	end
end

function LGameUI:CheckShowActScroll()
	local isShow = true

	local wndGuide = GF.FindFirstWndByName("UIGue")
	if wndGuide then
		if wndGuide:IsActScrollHide() then
			isShow = false
		end
	end

	if isShow then
		local wnd = self:FindMainAffectWnd()
		if wnd then
			if wnd:IsActScrollHide() or wnd:IsHideHurdle() then
				isShow = false
			end
		end
	end

	FireEvent(EventNames.SHOW_MAIN_ACTSCROLL,isShow)
end

function LGameUI:FindMainAffectWnd()
	local wndList = self._openWndList_sortLayer[LGameUI.UI_SORTLAYER_UIGUIDE]
	if wndList then
		local cnt = #wndList
		for k= cnt,1,-1 do
			local wnd = wndList[k]
			local wndName = wnd:GetWndName()
			if not LGameUI.NO_MAIN_AFFECT[wndName] then
				return wnd
			end
		end
	end


	wndList = self._openWndList_sortLayer[LGameUI.UI_SORTLAYER_UIWND]
	if wndList then
		local cnt = #wndList
		for k= cnt,1,-1 do
			local wnd = wndList[k]
			local wndName = wnd:GetWndName()
			if not LGameUI.NO_MAIN_AFFECT[wndName] and wnd:IsUnderMainCity() then
				return wnd
			end
		end
	end
end

function LGameUI:ChangeMainCityShow()
	self:CheckShowActScroll()
	self:CheckShowHurdle()
	self:CheckShowMainTop()
	self:CheckShowMainBottom()

	FireEvent(EventNames.ON_MAIN_CITY_SHOWREFRESH)
end

local _justMainNotEffectNames = {
	["UISayFlow"] = true,
	["UITkTips"] = true,
	["UIBzTips"] = true ,
	["UIMCity"] = true ,
	["UIQstTip"] = true ,

}

function LGameUI:IsJustMain()
	local wndList = self._openWndList_sortLayer[LGameUI.UI_SORTLAYER_UIWND]
	local isRet = false
	if wndList then
		local cnt = #wndList
		for k= cnt,1,-1 do
			local wnd = wndList[k]
			local wndName = wnd:GetWndName()
			if not LGameUI.NO_MAIN_AFFECT[wndName] and not _justMainNotEffectNames[wndName] then
				return false
			end
			if wndName == "UIMCity" then
				isRet = true
			end
		end
	end
	return isRet
end


function LGameUI:IsCurMainClean(includeWnd)
	includeWnd = includeWnd or {}
	for k,v in pairs(self._openWndList_wndName) do
		if not LGameUI.CLEAN_MAIN_INCLUDES[k] and not includeWnd[k] and #v > 0 then
			return false
		end
	end
	return true
end

function LGameUI:IsExistOneWnd(wndMap)
	for k,v in pairs(self._openWndList_wndName) do
		if wndMap[k] and #v > 0 then
			return true, k
		end
	end
	return false, nil
end

function LGameUI:IsUILayer(layer)
	if not self._uiLayerMap then
		self._uiLayerMap =
		{
			[LWnd.WND_LAYER] = true,
			[LWnd.WND_LAYER_EXTEND] = true,
		}
	end

	return self._uiLayerMap[layer]
end
