-- 用来保存正在做打开动画的界面
function LGameUI:AddOpenAniCount(cnt)
	self._openWndAniCnt = self._openWndAniCnt + cnt
	if self._openWndAniCnt < 0 then
		self._openWndAniCnt = 0
	end 
	return self._openWndAniCnt
end
function LGameUI:GetOpenAniCount()
	return self._openWndAniCnt
end


function LGameUI:GetPlayModule()
	local module = LPlayModuleConst.NONE

	local mainScene = GF.GetMainScene()
	if mainScene then
		module = mainScene:GetPlayModule()
		if module ~= LPlayModuleConst.NONE then
			return module
		end
	end

	local wndLayerList = self._openWndList_sortLayer
	local layerNameList = LGameUI.LAYER_NAME_LIST
	local layerCnt = #layerNameList
	local wndList
	local layerName
	local wndCnt
	local wnd
	for i = layerCnt, 1, -1 do
		layerName = layerNameList[i]
		wndList = wndLayerList[layerName]
		if wndList then
			wndCnt = #wndList
			for k=wndCnt, 1, -1 do
				wnd = wndList[k]
				local temp = wnd:GetPlayModuleBelong()
				if temp ~= module then
					module = temp
					break
				end
			end
		end
	end

	return module
end

function LGameUI:CheckPopWnd()
	local oldPlay = self._curPlay or LPlayModuleConst.NONE
	local curPlay = self:GetPlayModule()
	if oldPlay~= curPlay then
		self._curPlay = curPlay
		if curPlay == LPlayModuleConst.NONE then
			if gModelWndPop then
				gModelWndPop:CheckPopWnd()
			end
		end

		if LOG_INFO_ENABLED then
			print(string.format("<color=red>----------------------cur play module %s</color>",curPlay))
		end
	end
end

