function LGameUI:OnBackWndCreate(wndName)
	local wndItem = self:FindBackWnd(wndName)
	if wndItem then
		self:ClearBackWnd(wndItem.closeWndName)
	end
end
function LGameUI:OnBackWndClose(wndName)
end
function LGameUI:ClearBackWnd(closeWndName)
	local backWndMap = self._backWndMap_wndName or {}
	self._backWndMap_wndName = backWndMap
	
	local backWndListMap = self._backWndListMap_wndName or {}
	self._backWndListMap_wndName = backWndListMap
	local backWndList = backWndListMap[closeWndName]
	
	if not backWndList then
		return false
	end
	
	local isCheck = false
	local wndCls = nil
	for i,wndItem in ipairs(backWndList) do
		isCheck = true
		backWndMap[wndItem.wndName] = nil
	end
	backWndListMap[closeWndName] = nil
	
	return isCheck
end

function LGameUI:SaveBackWnd(closeWndName)
	local curMapName = nil
	local curMapArg = nil
	local curMap = GF.GetCurMap()
	if curMap then
		curMapName = curMap:GetMapClassName()
		curMapArg = curMap:GetMapArgList()
	end
	
	if curMapName and LGameUI.NO_RECORD_MAP[curMapName] then
		return
	end
	
	local backWndMap = self._backWndMap_wndName or {}
	self._backWndMap_wndName = backWndMap
	
	local backWndListMap = self._backWndListMap_wndName or {}
	self._backWndListMap_wndName = backWndListMap
	local backWndList = {}
	backWndListMap[closeWndName] = backWndList

	local wndArgList = nil
	local wndSortOrder = nil
	local wndSortLayer = nil
	
	for wndName,wndList in pairs(self._openWndList_wndName) do
		if not LGameUI.NO_BACK_WND_LIST[wndName] then
			for i,wndCls in ipairs(wndList) do
				
				local wndItem = {
					closeWndName = closeWndName,
					wndName = wndCls:GetWndName(),
					wndArgList = wndCls:GetWndArgList() or {},
					wndSortOrder = wndCls:GetWndSortOrder(),
					wndSortLayer = wndCls:GetWndSortLayer(),
					mapName = curMapName,
					mapArg = curMapArg
				}
				
				backWndMap[wndName] = wndItem
				table.insert(backWndList, wndItem)
			end
		end
	end

	table.sort(backWndList,function (a,b)
		return a.wndSortOrder < b.wndSortOrder
	end)
	
end

function LGameUI:FindBackWnd(wndName)
	local backWndMap = self._backWndMap_wndName or {}
	self._backWndMap_wndName = backWndMap
	
	return backWndMap[wndName]
end

function LGameUI:OpenBackWnd(closeWndName)
	local backWndMap = self._backWndMap_wndName or {}
	self._backWndMap_wndName = backWndMap
	
	local backWndListMap = self._backWndListMap_wndName or {}
	self._backWndListMap_wndName = backWndListMap
	local backWndList = backWndListMap[closeWndName]
	
	if not backWndList then
		return false
	end
	
	local curMapName = nil
	local curMap = GF.GetCurMap()
	if curMap then
		curMapName = curMap:GetMapClassName()
	end

	local isCheck = false
	local wndCls = nil
	for i,wndItem in ipairs(backWndList) do
		isCheck = true
		backWndMap[wndItem.wndName] = nil
		if curMapName ~= wndItem.mapName then
			curMapName = wndItem.mapName
			GF.ChangeMap(wndItem.mapName, false, wndItem.mapArg)
		end
		if not self:FindWndByName(wndItem.wndName) then
			local wndCls = self:OpenWndWithLayer(wndItem.wndSortLayer, wndItem.wndName, wndItem.wndArgList)
			if wndCls then
				wndCls:SetBackOpen(true)
			end
		end
	end
	
	backWndListMap[closeWndName] = nil
	
	return isCheck
end

function LGameUI:OnBackPressed()

	local isEditor = CS.IsUnityEdit()
	--TODO 暂时屏蔽
	if true then return end
	local isForeign = gLGameLanguage:IsOtherLngRegion()
	if not (isEditor or isForeign) then
		return
	end

	local isJapan = LGameSettings.platformRegion  == LRegionConst.JAPAN

	if not isJapan then
		if self:IsExistOneWnd(LGameUI.BACK_PRESS_NO_RESPONSE_WND) then
			return
		end

		if gModelGuide:HasWaitGuide() then
			return
		end
	end

	local ignoreWndRecord = self._ignoreWndRecord
	if not ignoreWndRecord then
		ignoreWndRecord = {}
		for k,v in pairs(LGameUI.ALL_CLOSE_EXCEPTS) do
			ignoreWndRecord[k] = true
		end

		for k,v in pairs(LGameUI.NO_AUTO_CLOSE_WND_LIST) do
			ignoreWndRecord[k] = true
		end

		for k,v in pairs(LGameUI.NO_CLEAN_CLOSE_WND_LIST) do
			ignoreWndRecord[k] = true
		end

		for k,v in pairs(GameTable.UIWindowBackBtnRef) do
			if v.closeType == 1 then
				ignoreWndRecord[v.refId] = true
			else
				ignoreWndRecord[v.refId] = nil
			end
		end
		self._ignoreWndRecord = ignoreWndRecord

	end


	local wnd = self:FindLastWnd(ignoreWndRecord)
	if not wnd then
		if GF.FindFirstWndByName("UIEtTip") then
			if gLGameLanguage:IsForeignRegion()
					and not gLGameLanguage:IsJapanRegion() then
				QuitGame()
			else
				GF.CloseWndByName("UIEtTip")
			end
		else
			gLSdkImpl:DoShowExitView()
		end
		return
	end
	local wndName = wnd:GetWndName()
	local backRef = GameTable.UIWindowBackBtnRef[wndName]
	local closeType,retBtnName;
	if backRef then
		closeType = backRef.closeType
		retBtnName = backRef.retBtnName
	end

	if closeType == 2 then
		wnd:ExecuteBtnFunc(retBtnName)
	else
		if LGameUI.SPECIAL_BACK_PRESS_WND[wndName] then
			wnd:ExecuteBackPress()
		else
			wnd:WndClose()
		end
	end
end

